export const AdminUpdateDormStatusParams = zod.object({
  "dormId": zod.coerce.number()
})

export const AdminUpdateDormStatusBody = zod.object({
  "status": zod.enum(['approved', 'rejected']),
  "note": zod.string().optional()
})

export const AdminUpdateDormStatusResponse = zod.object({
  "id": zod.number(),
  "ownerId": zod.number(),
  "name": zod.string(),
  "description": zod.string(),
  "monthlyRent": zod.number(),
  "address": zod.string(),
  "latitude": zod.number().nullish(),
  "longitude": zod.number().nullish(),
  "amenities": zod.array(zod.string()),
  "totalRooms": zod.number(),
  "bedsPerRoom": zod.number(),
  "availableBeds": zod.number(),
  "status": zod.enum(['pending', 'approved', 'rejected']),
  "coverPhotoUrl": zod.string().nullish(),
  "averageRating": zod.number().nullish(),
  "totalReviews": zod.number(),
  "createdAt": zod.string()
})


/**
 * @summary Admin dashboard stats
 */
export const AdminGetStatsResponse = zod.object({
  "totalUsers": zod.number(),
  "totalStudents": zod.number(),
  "totalOwners": zod.number(),
  "pendingVerifications": zod.number(),
  "totalDorms": zod.number(),
  "pendingDorms": zod.number(),
  "approvedDorms": zod.number(),
  "totalAppointments": zod.number(),
  "pendingAppointments": zod.number()
})


